use std::error::Error;

trait Action {
    fn execute(&self) -> Result<String, Box<dyn Error>>;
}

struct SaveAction;
impl Action for SaveAction {
    fn execute(&self) -> Result<String, Box<dyn Error>> {
        Ok("Data saved successfully".to_string())
    }
}

struct DeleteAction;
impl Action for DeleteAction {
    fn execute(&self) -> Result<String, Box<dyn Error>> {
        Ok("Record deleted from storage".to_string())
    }
}

struct ProcessAction;
impl Action for ProcessAction {
    fn execute(&self) -> Result<String, Box<dyn Error>> {
        Ok("Processing complete based on new logic path".to_string())
    }
}

fn run_action(action: &dyn Action) -> Result<(), Box<dyn Error>> {
    match action.execute()? {
        s if s == "Data saved successfully" => println!("Status: Success!"),
        s if s.contains("Delete") => println!("Status: Deletion Handled."),
        _ => println!("Status: General Result Received.")
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let save_action = SaveAction;
    run_action(&save_action)?;

    let delete_action = DeleteAction;
    run_action(&delete_action)?;

    let process_action = ProcessAction;
    run_action(&process_action)?;

    Ok(())
}

use std::collections::HashMap;

trait Behavior {
    fn execute(&self, context: &mut GameContext) -> String;
}

struct MoveBehavior;
impl Behavior for MoveBehavior {
    fn execute(&self, context: &mut GameContext) -> String {
        context.player_x += 1;
        format!("Player moved to ({}, {})", context.player_x, context.player_y)
    }
}

struct AttackBehavior;
impl Behavior for AttackBehavior {
    fn execute(&self, context: &mut GameContext) -> String {
        let damage = 10;
        context.enemy_health -= damage;
        format!("Player attacked enemy for {} damage. New health: {}", damage, context.enemy_health)
    }
}

struct GameContext {
    player_x: i32,
    player_y: i32,
    enemy_health: i32,
}

fn main() {
    let mut context = GameContext { 
        player_x: 0, 
        player_y: 0, 
        enemy_health: 50 
    };

    let mut available_actions: HashMap<String, Box<dyn Behavior>> = HashMap::new();

    available_actions.insert("move".to_string(), Box::new(MoveBehavior));
    available_actions.insert("attack".to_string(), Box::new(AttackBehavior));

    let action_key = "attack".to_string();

    if let Some(action) = available_actions.get(&action_key) {
        let result = action.execute(&mut context);
        println!("Action executed successfully: {}", result);
    }
}

use std::collections::HashMap;

struct StrategyContext {
    operation: Box<dyn Operation>, 
}

impl StrategyContext {
    fn new(operation: Box<dyn Operation>) -> Self {
        StrategyContext { operation }
    }

    fn execute_transform(&self, data_vector: Vec<f64>) -> Result<Vec<f64>, &'static str> {
        self.operation.apply(&data_vector)
    }
}

trait Operation {
    fn apply(&self, data: &[f64]) -> Result<Vec<f64>, &'static str>;
}

struct MeanOperation;
impl Operation for MeanOperation {
    fn apply(&self, data: &[f64]) -> Result<Vec<f64>, &'static str> {
        if data.is_empty() {
            return Err("Cannot calculate mean of an empty set.");
        }
        let sum: f64 = data.iter().sum();
        let result = vec![sum / (data.len() as f64)];
        Ok(result)
    }
}

struct StdDevOperation;
impl Operation for StdDevOperation {
    fn apply(&self, data: &[f64]) -> Result<Vec<f64>, &'static str> {
        if data.len() < 2 {
            return Err("Need at least two samples for standard deviation.");
        }
        let mean = data.iter().sum::<f64>() / (data.len() as f64);
        let variance: f64 = data.iter().map(|&x| (x - mean).powi(2)).sum::<f64>() / ((data.len() - 1) as f64);
        let result = vec![variance.sqrt()];
        Ok(result)
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let data_points = vec![10.0, 20.0, 30.0];

    let mean_strategy: Box<dyn Operation> = Box::new(MeanOperation);
    let context_mean = StrategyContext::new(mean_strategy);
    println!("Mean result: {:?}", context_mean.execute_transform(data_points.clone())?);

    let stddev_strategy: Box<dyn Operation> = Box::new(StdDevOperation);
    let context_stddev = StrategyContext::new(stddev_strategy);
    println!("StdDev result: {:?}", context_stddev.execute_transform(data_points)?);

    Ok(())
}

use std::collections::HashMap;

struct BinaryContext {
    data: Vec<u8>,
}

impl BinaryContext {
    fn new(data: Vec<u8>) -> Self {
        BinaryContext { data }
    }
}

trait Validator {
    fn validate(&self, context: &mut BinaryContext) -> Result<(), String>;
}

struct MagicNumberValidator;

impl Validator for MagicNumberValidator {
    fn validate(&self, context: &mut BinaryContext) -> Result<(), String> {
        if context.data.len() < 4 {
            return Err("File is too short to check magic number".to_string());
        }
        let magic = u32::from_le_bytes([context.data[0], context.data[1], context.data[2], context.data[3]]);
        if magic != 0x7f61bd22 {
            return Err("Invalid ELF signature".to_string());
        }
        Ok(())
    }
}

struct SectionHeaderValidator;

impl Validator for SectionHeaderValidator {
    fn validate(&self, context: &mut BinaryContext) -> Result<(), String> {
        if context.data.len() < 1024 {
            return Err("File is smaller than expected to contain section headers".to_string());
        }
        Ok(())
    }
}

struct Loader {
    validators: Vec<Box<dyn Validator>>,
}

impl Loader {
    fn new() -> Self {
        Loader {
            validators: vec![Box::new(MagicNumberValidator), Box::new(SectionHeaderValidator)],
        }
    }

    fn load_and_validate(&self, data: Vec<u8>) -> Result<(), String> {
        let mut context = BinaryContext::new(data);
        for validator in &self.validators {
            validator.validate(&mut context)?;
        }
        Ok(())
    }
}

